<div class="flex justify-content-between align-items-center mb-3">
  <h2>רשימת תורמים</h2>

  <button
    pButton
    label="הוספת תורם"
    icon="pi pi-plus"
    class="p-button-success"
    (click)="showAddDialog()">
  </button>
</div>

<!-- Dialog של הוספת תורם -->
<p-dialog header="הוספת תורם" [(visible)]="addDialogVisible" [modal]="true" [closable]="true"     [style]="{width: '400px'}">
  <div class="p-fluid">
    <div class="p-field">
      <label for="firstName">שם פרטי</label>
      <input id="firstName" type="text" pInputText [(ngModel)]="newDonor.firstName" />
    </div>
    <div class="p-field">
      <label for="lastName">שם משפחה</label>
      <input id="lastName" type="text" pInputText [(ngModel)]="newDonor.lastName" />
    </div>
    <div class="p-field">
      <label for="email">מייל</label>
      <input id="email" type="email" pInputText [(ngModel)]="newDonor.emailAddress" />
    </div>
    <div class="p-field">
      <label for="phone">טלפון</label>
      <input id="phone" type="text" pInputText [(ngModel)]="newDonor.phone" />
    </div>
  </div>

  <p-footer>
    <button pButton label="ביטול" class="p-button-text" (click)="addDialogVisible=false" > </button>
    <button pButton label="שמירה" class="p-button-primary" (click)="addDonor()"></button>
  </p-footer>
</p-dialog>

<p-table [value]="donors" [paginator]="true" [rows]="10">

  <ng-template pTemplate="header">
    <tr>
     <th>FirstName</th>
      <th>LastName</th>
      <th>Email</th>
      <th>Phone</th>
      <th>My Gifts</th>
    </tr>
  </ng-template>

  <ng-template pTemplate="body" let-donor>
    <tr>
      <td>{{ donor.firstName }}</td>
      <td>{{ donor.lastName }}</td>
      <td>{{ donor.email  }}</td>
      <td>{{ donor.phone }}</td>
      <td> <a [routerLink]="['/donor-gifts', donor.id]" class="donor-link">
        myGifts
        </a></td>
    </tr>
  </ng-template>

</p-table>
